import{_ as i,o as r,c as t,ae as l}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"Recursive Regime Resilience","description":"","frontmatter":{},"headers":[],"relativePath":"resilience/regime-switching.md","filePath":"resilience/regime-switching.md"}'),o={name:"resilience/regime-switching.md"};function s(n,e,a,c,g,m){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="recursive-regime-resilience" tabindex="-1">Recursive Regime Resilience <a class="header-anchor" href="#recursive-regime-resilience" aria-label="Permalink to &quot;Recursive Regime Resilience&quot;">​</a></h1><p><strong>&quot;시장은 살아있는 유기체와 같습니다. 전략 역시 시장의 호흡에 따라 그 모습을 바꾸어야 합니다.&quot;</strong> - WeJump Labs</p><hr><h2 id="🏛️-1-평상시-normal-vs-예외-extreme-국면" tabindex="-1">🏛️ 1. 평상시(Normal) vs 예외(Extreme) 국면 <a class="header-anchor" href="#🏛️-1-평상시-normal-vs-예외-extreme-국면" aria-label="Permalink to &quot;🏛️ 1. 평상시(Normal) vs 예외(Extreme) 국면&quot;">​</a></h2><p>CBVR v2.3은 시장의 &#39;체질&#39;에 따라 완전히 다른 두 가지 논리 체계를 가동합니다.</p><ul><li><strong>Normal Regime (평상시):</strong><ul><li>특징: 채널 내에서의 변동성 (Envelope Strategy).</li><li>로직: 평균회귀(Mean Reversion) 모듈 활성화.</li></ul></li><li><strong>Extreme Regime (예외 국면):</strong><ul><li>특징: 강력한 일방향 추세 또는 변동성의 폭발.</li><li>로직: <strong>추세순응 헤지(Trend Following Hedge)</strong> 모듈 강제 활성화.</li></ul></li></ul><h2 id="🔄-2-재귀적-리스크-제어-reflexivity" tabindex="-1">🔄 2. 재귀적 리스크 제어 (Reflexivity) <a class="header-anchor" href="#🔄-2-재귀적-리스크-제어-reflexivity" aria-label="Permalink to &quot;🔄 2. 재귀적 리스크 제어 (Reflexivity)&quot;">​</a></h2><p>Soros의 재귀성 이론을 계승하여, 전략의 **현재 성과 곡선(Equity Curve)**을 시스템의 피드백 루프로 사용합니다.</p><ul><li><strong>자정 작용:</strong> 전략 자체가 예상 밖의 손실을 겪을 때, 수치적 한계를 넘어서는 위험 감지 시 자발적 디레버리징(Deleveraging)을 발동합니다.</li><li><strong>생존 최우선:</strong> 수익을 내는 것이 아니라 **&#39;죽지 않는 것&#39;**이 이 모듈의 존재 이유입니다.</li></ul><hr><blockquote><p><strong>Key Insight:</strong> &quot;레짐 체인지는 &#39;예측&#39;하는 것이 아니라, <strong>이미 변화된 수치</strong>를 받아들이는 즉시 실행하는 것입니다.&quot; 🐯🐾</p></blockquote>',11)])])}const d=i(o,[["render",s]]);export{h as __pageData,d as default};
